class Solution {
    public int[][] validArrangement(int[][] pairs) {
        Map<Integer, List<int[]>> graph = new HashMap<>();
        int n = pairs.length;
        for (int[] pair : pairs) {
            graph.computeIfAbsent(pair[0], k -> new ArrayList<>()).add(pair);
            graph.computeIfAbsent(pair[1], k -> new ArrayList<>());
        }
        int[] inDegree = new int[100001];
        for (int[] pair : pairs) {
            inDegree[pair[1]]++;
        }
        int start = -1;
        for (int i = 0; i < 100001; i++) {
            if (graph.containsKey(i) && inDegree[i] == graph.get(i).size() - 1) {
                start = i;
                break;
            }
        }
        int[][] result = new int[n][2];
        int index = 0;
        while (!graph.get(start).isEmpty()) {
            int[] pair = graph.get(start).remove(graph.get(start).size() - 1);
            result[index++] = pair;
            start = pair[1];
        }
        return result;
    }
}
